; ラドミラの塔

name = ラドミラの塔17Ｆ
insideName = 17Ｆ
upper = ラドミラの塔18Ｆ
lower = ラドミラの塔16Ｆ
level = 66
bgm = tower
shadow = dark
sky = dawnforest
roof = stone
margin = 3

; パーツ画像
━ = stone_h
　 = marble
〰 = water
／ = door
∫ = pick
⧻ = fence
☖ = arch
︻ = panel
┯ = button

; 敵情報
monsters = マンイーター,怒りの霊魂,サイクロプス,ゴールドマン,ケイブジャイアント

; 宝箱
box[1] = 師範の腕輪_u,ボム,ボム

